from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character (or related entities)
    into a single fluent English sentence.
    """
    if not triples:
        return ""

    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        if p == "alternativeName":
            parts.append(f"{s} is also known as {o}")
        elif p == "creator":
            parts.append(f"{s} was created by {o}")
        elif p == "fullName":
            parts.append(f"{s}'s full name is {o}")
        elif p == "foundedBy":
            parts.append(f"{s} was founded by {o}")
        elif p == "keyPerson":
            parts.append(f"{s} has key person {o}")
        elif p == "city":
            parts.append(f"{s} is located in {o}")
        elif p == "product":
            parts.append(f"{s} produces {o}")
        elif p == "lastAired":
            parts.append(f"The last episode of {s} aired on {o}")
        elif p == "starring":
            parts.append(f"{s} stars {o}")
        elif p == "firstAppearanceInFilm":
            parts.append(f"{s} first appeared in the film {o}")
        elif p == "voice":
            parts.append(f"{s} is voiced by {o}")
        elif p == "distributor":
            parts.append(f"The film {s} was distributed by {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "nationality":
            # Choose correct indefinite article
            article = "an" if o[:1].lower() in "aeiou" else "a"
            parts.append(f"{s} is {article} {o} national")
        elif p == "award":
            parts.append(f"{s} received the {o}")
        elif p == "broadcastedBy":
            parts.append(f"{s} was broadcasted by {o}")
        elif p == "firstAired":
            parts.append(f"{s} first aired on {o}")
        elif p == "series":
            parts.append(f"{s} belongs to the series {o}")
        elif p == "child":
            parts.append(f"{s} has a child named {o}")
        else:
            parts.append(f"{s} {p} {o}")

    # Combine parts into a single fluent sentence
    if not parts:
        return ""
    if len(parts) == 1:
        sentence = parts[0] + "."
    else:
        # Use semicolons for separation and a final conjunction for readability
        sentence = "; ".join(parts[:-1]) + ", and " + parts[-1] + "."
    return sentence

